    public partial class TradeCreateCommand : AbstractCommand
    {
        protected readonly TradeListVM _viewModel;
        private readonly IWindowDialogService _windowDialogService;
        private readonly ISymbolLookupService _symbolLookupService;
        private readonly ITradingAccountLookupService _tradingAccountLookupService;
        
        public TradeCreateCommand(TradeListVM viewModel, IWindowDialogService windowDialogService,
                                  ISymbolLookupService symbolLookupService, ITradingAccountLookupService tradingAccountLookupService)
        {
            _viewModel = viewModel;
            _windowDialogService = windowDialogService;
            _symbolLookupService = symbolLookupService;
            _tradingAccountLookupService = tradingAccountLookupService;
        }

        public override async void Execute(object? parameter)
        {
            if (parameter is not Window owner)
                return;

            try
            {
                var dialogResult = _windowDialogService.ShowTradeCreateDialog(owner, _symbolLookupService, _tradingAccountLookupService, PreselectedTradingAccount);

                if (dialogResult.IsConfirmed && dialogResult.Trade is not null)
                {
                    var trade = dialogResult.Trade;
                    await _viewModel.SaveTradeAsync(trade);
                    await _viewModel.LoadTradesAsync();

